SELECT GENERO FROM (SELECT S.GENERO AS GENERO, COUNT(*) AS PARTICIPACOES FROM CALC_HORA_AULA_MEDIA CH JOIN SERVIDOR S ON CH.SIAPE = S.PK_SIAPE JOIN CURSO C ON CH.SIGLA_CURSO = C.SIGLA WHERE LOWER(CH.SIGLA_CAMPUS) = 'for' AND LOWER(CH.AREA_INGRESSO) LIKE '%letras%' AND LOWER(C.MODALIDADE) LIKE '%integrado%' AND LOWER(C.NIVEL) = 'ensino medio' AND CH.ANO >= (CAST(strftime('%Y', 'now') AS INTEGER) - 4) GROUP BY S.GENERO ORDER BY PARTICIPACOES DESC LIMIT 1) AS t